// // This module is designed to divide an input count by 8 using sequential logic. It takes a clock input and a reset signal. The output is a 3-bit value representing the quotient of the input count divided by 8.
module divide_by_8(
    input clk,
    input rst,
    output reg [2:0] q
);
    reg [2:0] count;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 3'b000;
            q <= 3'b000;
        end else begin
            if (count == 3'b111) begin
                count <= 3'b000;
                q <= q + 1;
            end else begin
                count <= count + 1;
            end
        end
    end
endmodule
